var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"절 길러주신 신부님은 가족이나 다름없는 분이셨어요.","JPN":"私を育ててくださった神父様は、私にとっては家族も同然でした。","ENG":"The priest who raised me was like family to me.","TWN":"撫養我的神父，對我而言和家人無異。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"narration","speaker":null,"text":{"KOREA":"그 분은 훗날 제가 어디에 속하게 되건, 그곳의 법도를 따라야 한다고 말씀하셨죠.","JPN":"神父様は将来私がどこに所属することになっても、そこのルールに従わねばならないと教えてくれました。","ENG":"He told me that no matter where I ended up, I had to follow the rules of that place.","TWN":"他曾說過，不論我將來歸屬哪裡，都必須遵守那裡的法則。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"narration","speaker":null,"text":{"KOREA":"제가 속한 구마회가 말하는 법도는 명료했어요.","JPN":"私が所属する祓魔会のルールは明確でした。","ENG":"The rules my exorcist order upheld were simple.","TWN":"而我所屬的驅魔會，法則非常明確。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"narration","speaker":null,"text":{"KOREA":"…악마를 멸하라.","JPN":"……悪魔を滅せよ。","ENG":"...Destroy the devils.","TWN":"……消滅魔鬼。"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"선봉구마사, 니콜 프라이머.","JPN":"先鋒エクソシスト、ニコル・プライマー。","ENG":"Vanguard Exorcist, Nicole Primer.","TWN":"先鋒驅魔師，妮可．布萊伊莫。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"우리에게 악마를 넘겨라.","JPN":"我らに悪魔を引き渡せ。","ENG":"Hand over the devil to us.","TWN":"把魔鬼交給我們。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그게… 갑자기 무슨 말씀이시죠?","JPN":"それは……急に何のお話でしょうか？","ENG":"W-what do you mean all of a sudden?","TWN":"你……這麼突然在說什麼？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"저는 아직 악마를 찾지 못했다고 보고를 드렸을 텐데…","JPN":"悪魔はまだ見つかっていない、と報告したはず……","ENG":"I reported that I still hadn't found any devil yet...","TWN":"我應該已經回報過，尚未找到魔鬼……"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"그대는 지금 악마의 간계에 빠진 것이다.","JPN":"そなたは今悪魔の計略にはまっている。","ENG":"You have fallen for a devil's deceit.","TWN":"你已墮入魔鬼的詭計。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"그로 말미암아 자신 본질을 잊고, 악마를 감싸는 지경에 이르렀구나.","JPN":"そのせいで己の務めを忘れ、ひいては悪魔を庇うまでになってしまったようだ。","ENG":"So much so that you've forgotten your true nature and now seek to protect it.","TWN":"因此忘卻自己的本質，甚至開始包庇魔鬼。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"모든 것을 아는 성황청은 더 이상 이를 좌시하지 않기로 했으며, 그대를 대신해 규례를 행하고자 우리를 보냈음이라.","JPN":"すべてを知る聖皇庁はこれ以上この件について傍観しないと決め、そなたに代わり悪魔を祓うため我らを派遣した。","ENG":"The Holy Curia, which knows all, has decided it can no longer overlook this. We were sent to carry out the rite in your stead.","TWN":"無所不知的聖皇廳已決定不再坐視不管，派我們前來代你執行戒律。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"악마는 이곳에 없습니다.","JPN":"ここに悪魔はいません。","ENG":"There is no devil here.","TWN":"這裡沒有魔鬼。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"펜듈럼을 가지고 있다면 보여라.","JPN":"ペンデュラムを持っているのなら見せよ。","ENG":"If you possess a pendulum, present it.","TWN":"若你持有鐘擺，就拿出來。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_SERIOUS2"}}}},{"id":"L27_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"그것이 향하는 곳에 악마가 있을 지니.","JPN":"それが示す方向に悪魔はいるであろう。","ENG":"Where it points, the devil will be found.","TWN":"它所指之處，便是魔鬼所在。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_SERIOUS2"}}}},{"id":"L28_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GREMORY_BAR","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_SERIOUS2"}}}},{"id":"L29_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"꺼낼 수 없겠지. 그럴 필요도 없으리라.","JPN":"取り出せるはずがない。また、その必要もない。","ENG":"You cannot bring it out. Nor is there any need.","TWN":"你拿不出來吧？其實也沒這個必要。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_SERIOUS2"}}}},{"id":"L30_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"그대는 이미 펜듈럼이 가리킬 방향을 알고 있을 테니.","JPN":"なぜならそなたはすでにペンデュラムが示す方向を知っているからだ。","ENG":"You already know where the pendulum would point.","TWN":"因為你早就知道鐘擺會指向哪裡。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_SERIOUS2"}}}},{"id":"L31_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"저는 지금 뭘 하고 있는 거죠?","JPN":"私は今何をしているのでしょう？","ENG":"What am I even doing right now?","TWN":"我現在到底在做什麼？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_SERIOUS2"}}}},{"id":"L32_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"이렇게 계속 저항하면… 돌이킬 수 없는 문제로 퍼지고 말아요.","JPN":"こうやって抵抗し続ければ……取り返しがつかなくなってしまいます。","ENG":"If I keep resisting like this... This will spiral into something irreversible.","TWN":"再這樣抵抗下去，只會演變成無法挽回的局面。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_SERIOUS2"}}}},{"id":"L33_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"결국 이런 순간이 올 줄은 알았지만… 왜 하필이면 지금…","JPN":"いつかはこの瞬間が訪れるとわかっていましたが……なぜよりによって今……","ENG":"I knew this moment would come someday... But why now...?","TWN":"我早就知道會有這一天……可為什麼偏偏是現在……"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_SERIOUS2"}}}},{"id":"L35_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GREMORY_BAR","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_SERIOUS2"}}}},{"id":"L36_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그러네요. 마주하게 될 일이란 걸 알고 있었어요.","JPN":"そうですね。いつか向き合うことになるとわかってはいたんです。","ENG":"You're right. I knew I would have to face this eventually.","TWN":"是啊，我知道遲早要面對。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_SERIOUS2"}}}},{"id":"L37_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아직 마음의 준비가 안 됐다는 건… 안일한 변명일 뿐이겠죠.","JPN":"まだ心の準備ができていない、というのは……都合のいい言い訳に過ぎませんよね。","ENG":"Saying I'm not ready yet... is just a weak excuse.","TWN":"說自己還沒做好心理準備……也只是安逸的藉口罷了。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_SERIOUS2"}}}},{"id":"L41_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"가게에서 소동은 용납하지 않겠습니다.","JPN":"お店で騒ぎを起こすのは許しません。","ENG":"I won't tolerate disturbance in my establishment.","TWN":"我不允許有人在店裡鬧事。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"손님이 아니라면… 지금 당장 나가주시죠.","JPN":"お客様でなければ……今すぐ出ていただきます。","ENG":"If you are not customers... then leave at once.","TWN":"若不是客人……請立刻離開。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"감히 무기를 겨누는가.","JPN":"我らに武器を向けるか。","ENG":"You dare raise a weapon?","TWN":"竟敢舉起武器。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CULTIST_NPC_NULL_QM","text":{"KOREA":"성황청이 그대에게 내린 그 무기를… 성황의 사도들에게 드리우는가?","JPN":"聖皇庁がそなたに授けたその武器を……聖皇の使徒に突きつけるというのか？","ENG":"That weapon, bestowed upon you by the Holy Curia... You would aim it at the Curia's own Apostles?","TWN":"你將聖皇廳賜予你的武器……指向聖皇的使徒嗎？"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_QM","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"이곳에서 저는…","JPN":"ここでの私は……","ENG":"Here, I'm...","TWN":"在這裡，我只是……"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"가게를 지키는 바텐더일 뿐입니다.","JPN":"店番をしているバーテンダーにすぎません。","ENG":"Nothing more than a bartender protecting her bar.","TWN":"守護店鋪的酒保而已。"},"stage":{"bg":"GREMORY_BAR","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};